-- Load UMKM Tumbuh schema-first generated CSV data.
-- Run from /app/data where csv/*.csv exists.
-- Intended for infra/db/dummy/seed-csv generated by generate_umkm_tumbuh_schema_first.py.
\set ON_ERROR_STOP on

-- =============================================================================
-- REFERENCE TABLES
-- =============================================================================

-- The schema migrations may already seed reference rows. For schema-first dummy loading,
-- make this loader own the reference IDs from csv/ref_*.csv so FK values generated
-- by the dummy generator cannot collide with pre-seeded lookup names.
-- Intended for clean/dev dummy seed runs. CASCADE will remove existing dependent dummy data.
TRUNCATE TABLE
  ref.ref_dimwaktu,
  ref.ref_jenisdokumen,
  ref.ref_statusdokumen,
  ref.ref_statusverifikasi,
  ref.ref_statusperkembangan,
  ref.ref_statuspengajuan,
  ref.ref_statussertifikat,
  ref.ref_statussubmission,
  ref.ref_statuspendaftaranpelatihan,
  ref.ref_statuspelatihan,
  ref.ref_jenispelatihan,
  ref.ref_statusmitra,
  ref.ref_statusumkm,
  ref.ref_skalakerjasama,
  ref.ref_bentukdukungan,
  ref.ref_bidangkemitraan,
  ref.ref_jenismitra,
  ref.ref_jenisumkm,
  ref.ref_kategoriproduk,
  ref.ref_kategoriusaha,
  ref.ref_skalausaha,
  ref.ref_peranpengguna
RESTART IDENTITY CASCADE;
CREATE TEMP TABLE _r (id VARCHAR(30), name VARCHAR(200));

\copy _r FROM 'csv/ref_skalausaha.csv' WITH (FORMAT csv, HEADER true, NULL '');
INSERT INTO ref.ref_skalausaha (skala_usaha_id, nama_skala_usaha)
SELECT id, name FROM _r
ON CONFLICT (skala_usaha_id) DO UPDATE SET nama_skala_usaha = EXCLUDED.nama_skala_usaha;
TRUNCATE _r;

