CREATE TEMP TABLE _rd AS SELECT
  jenis_dokumen_id,
  nama_jenis_dokumen,
  deskripsi,
  allowed_extensions,
  max_size_mb,
  wajib_umkm,
  wajib_mitra,
  wajib_pengajuan_kemitraan
FROM ref.ref_jenisdokumen WHERE false;
\copy _rd FROM 'csv/ref_jenisdokumen.csv' WITH (FORMAT csv, HEADER true, NULL '');
INSERT INTO ref.ref_jenisdokumen (
  jenis_dokumen_id, nama_jenis_dokumen, deskripsi, allowed_extensions,
  max_size_mb, wajib_umkm, wajib_mitra, wajib_pengajuan_kemitraan
)
SELECT * FROM _rd
ON CONFLICT (jenis_dokumen_id) DO UPDATE SET
  nama_jenis_dokumen = EXCLUDED.nama_jenis_dokumen,
  deskripsi = EXCLUDED.deskripsi,
  allowed_extensions = EXCLUDED.allowed_extensions,
  max_size_mb = EXCLUDED.max_size_mb,
  wajib_umkm = EXCLUDED.wajib_umkm,
  wajib_mitra = EXCLUDED.wajib_mitra,
  wajib_pengajuan_kemitraan = EXCLUDED.wajib_pengajuan_kemitraan;
DROP TABLE _rd;

