-- =============================================================================
-- POST-LOAD SEQUENCE SYNC FOR TABLES WITH OPTIONAL GENERATED IDS
-- =============================================================================
-- Keep this safe even if tables do not use serial/bigserial ids.
DO $$
DECLARE
  r RECORD;
BEGIN
  FOR r IN
    SELECT
      n.nspname AS schema_name,
      c.relname AS table_name,
      a.attname AS column_name,
      pg_get_serial_sequence(format('%I.%I', n.nspname, c.relname), a.attname) AS seq_name
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    JOIN pg_attribute a ON a.attrelid = c.oid
    WHERE c.relkind = 'r'
      AND n.nspname IN ('auth', 'user_mgmt', 'training', 'document', 'partnership', 'dashboard')
      AND a.attnum > 0
      AND NOT a.attisdropped
  LOOP
    IF r.seq_name IS NOT NULL THEN
      EXECUTE format(
        'SELECT setval(%L, COALESCE((SELECT MAX(%I)::bigint FROM %I.%I), 1), true)',
        r.seq_name,
        r.column_name,
        r.schema_name,
        r.table_name
      );
    END IF;
  END LOOP;
END $$;

SELECT 'schema-first dummy CSV load completed' AS message;
